def metric(example, pred, trace=None):
    import re
    STOP = {'the','a','an','is','are','was','were','be','been','being','have','has','had','do','does','did','will','would','could','should','may','might','shall','can','need','dare','ought','used','to','of','in','for','on','with','at','by','from','as','into','through','during','before','after','above','below','between','out','off','over','under','again','further','then','once','here','there','when','where','why','how','all','each','every','both','few','more','most','other','some','such','no','not','only','own','same','so','than','too','very','just','because','but','and','or','if','while','that','this','it','i','me','my','you','your','we','our','they','their','he','she','him','her','his','its'}
    def tokenize(text):
        words = set(re.findall(r'\b[a-z]+\b', str(text).lower()))
        return words - STOP
    persona_words = tokenize(getattr(example, 'persona_context', ''))
    response_words = tokenize(getattr(pred, 'response', ''))
    if not persona_words or not response_words:
        return 0.0
    intersection = persona_words & response_words
    union = persona_words | response_words
    return len(intersection) / len(union) if union else 0.0

def metric(example, pred, trace=None):
    import re
    def avg_len(text):
        sents = [s.strip() for s in re.split(r'[.!?]+', str(text)) if s.strip()]
        if not sents: return 10.0
        return sum(len(s.split()) for s in sents) / len(sents)
    persona_avg = avg_len(getattr(example, 'persona_context', ''))
    response_avg = avg_len(getattr(pred, 'response', ''))
    if persona_avg == 0: return 0.0
    delta = abs(persona_avg - response_avg) / persona_avg
    return max(0.0, 1.0 - delta)

def metric(example, pred, trace=None):
    import re
    STOP = {'the','a','an','is','are','was','were','be','been','have','has','had','do','does','did','will','would','could','should','to','of','in','for','on','with','at','by','from','as','and','or','but','not','so','if','it','i','me','my','you','your','we','they','this','that'}
    def keywords(text):
        words = set(re.findall(r'\b[a-z]+\b', str(text).lower()))
        return words - STOP
    msg_kw = keywords(getattr(example, 'message_to_reply_to', ''))
    resp_kw = keywords(getattr(pred, 'response', ''))
    if not msg_kw: return 1.0
    overlap = msg_kw & resp_kw
    return len(overlap) / len(msg_kw)
